18: const StateHistoryWriteTimeout = time.Minute
19: 
20: func shouldRecord(transition state.StateTransition) bool {
21: 	if !transition.Changed() {
22: 		return false
23: 	}
24: 
25: 	// Do not log not transitioned states normal states if it was marked as stale
26: 	if transition.StateReason == models.StateReasonMissingSeries && transition.PreviousState == eval.Normal && transition.State.State == eval.Normal {
27: 		return false
28: 	}
29: 	// Do not log transition from Normal (Paused|Updated) to Normal
30: 	if transition.State.State == eval.Normal && transition.StateReason == "" &&
31: 		transition.PreviousState == eval.Normal && (transition.PreviousStateReason == models.StateReasonPaused || transition.PreviousStateReason == models.StateReasonUpdated) {
32: 		return false
33: 	}
34: 	return true
35: }
36: 
37: // ShouldRecordAnnotation returns true if an annotation should be created for a given state transition.
38: // This is stricter than shouldRecord to avoid cluttering panels with state transitions.
39: func ShouldRecordAnnotation(t state.StateTransition) bool {
40: 	if !shouldRecord(t) {
41: 		return false
42: 	}
43: 
44: 	// Do not log transitions when keeping last state
45: 	toKeepLast := strings.Contains(t.StateReason, models.StateReasonKeepLast) && !strings.Contains(t.PreviousStateReason, models.StateReasonKeepLast)
46: 	if toKeepLast {
47: 		return false
48: 	}
49: 
50: 	// Do not record transitions between Normal and Normal (NoData)
51: 	if t.State.State == eval.Normal && t.PreviousState == eval.Normal {
52: 		if (t.StateReason == "" && t.PreviousStateReason == models.StateReasonNoData) ||
53: 			(t.StateReason == models.StateReasonNoData && t.PreviousStateReason == "") {
54: 			return false
55: 		}
56: 	}
57: 
58: 	return true
59: }
