77: // PanelKey uniquely identifies a panel.
78: type PanelKey struct {
79: 	orgID   int64
80: 	dashUID string
81: 	panelID int64
82: }
83: 
84: func NewPanelKey(orgID int64, dashUID string, panelID int64) PanelKey {
85: 	return PanelKey{
86: 		orgID:   orgID,
87: 		dashUID: dashUID,
88: 		panelID: panelID,
89: 	}
90: }
91: 
92: // PanelKey attempts to get the key of the panel attached to the given rule. Returns nil if the rule is not attached to a panel.
93: func parsePanelKey(rule history_model.RuleMeta, logger log.Logger) *PanelKey {
94: 	if rule.DashboardUID != "" {
95: 		key := NewPanelKey(rule.OrgID, rule.DashboardUID, rule.PanelID)
96: 		return &key
97: 	}
98: 	return nil
99: }
